import { S3Client, PutObjectCommand, GetObjectCommand } from "@aws-sdk/client-s3";
import { DynamoDBClient } from "@aws-sdk/client-dynamodb";
import { DynamoDBDocumentClient, PutCommand, GetCommand, QueryCommand } from "@aws-sdk/lib-dynamodb";

// S3 client — region auto-detected from AWS_DEFAULT_REGION or config file
const s3 = new S3Client({ region: "us-east-1" });

// Upload a file
await s3.send(new PutObjectCommand({
  Bucket: "my-bucket",
  Key: "data/record.json",
  Body: JSON.stringify({ id: 1, value: "test" }),
  ContentType: "application/json",
}));

// Download and read the response stream (Node.js)
const response = await s3.send(new GetObjectCommand({
  Bucket: "my-bucket",
  Key: "data/record.json",
}));
const body = await response.Body?.transformToString();
console.log(JSON.parse(body ?? "{}"));

// DynamoDB — use DynamoDBDocumentClient to avoid type marshalling boilerplate
const ddb = new DynamoDBClient({ region: "us-east-1" });
const docClient = DynamoDBDocumentClient.from(ddb);

await docClient.send(new PutCommand({
  TableName: "orders",
  Item: { order_id: "ORD-001", status: "pending", amount: 99.99 }
}));

const { Item } = await docClient.send(new GetCommand({
  TableName: "orders",
  Key: { order_id: "ORD-001" }
}));
console.log(Item?.status);

