import software.amazon.awssdk.regions.Region;
import software.amazon.awssdk.services.s3.S3Client;
import software.amazon.awssdk.services.s3.model.*;
import software.amazon.awssdk.core.sync.RequestBody;
import java.nio.file.Paths;

S3Client s3 = S3Client.builder()
    .region(Region.US_EAST_1)
    .build();

// Upload a file
s3.putObject(
    PutObjectRequest.builder()
        .bucket("my-bucket")
        .key("data/record.json")
        .contentType("application/json")
        .serverSideEncryption(ServerSideEncryption.AWS_KMS)
        .build(),
    RequestBody.fromString("{"id": 1}")
);

// List objects with prefix
ListObjectsV2Response result = s3.listObjectsV2(
    ListObjectsV2Request.builder()
        .bucket("my-bucket")
        .prefix("data/")
        .maxKeys(100)
        .build()
);
result.contents().forEach(obj ->
    System.out.println(obj.key() + " " + obj.size())
);

// Always close clients (use try-with-resources in practice)
s3.close();

import boto3
from botocore.exceptions import ClientError
from botocore.config import Config

# Configure retries
config = Config(
    retries={'mode': 'standard', 'max_attempts': 10},
    connect_timeout=5,
    read_timeout=30,
)
s3 = boto3.client('s3', config=config)

def get_object_safe(bucket: str, key: str) -> bytes | None:
    """Get an S3 object with specific error handling."""
    try:
        response = s3.get_object(Bucket=bucket, Key=key)
        return response['Body'].read()
    except ClientError as e:
        error_code = e.response['Error']['Code']
        if error_code == 'NoSuchKey':
            # Object does not exist — handle gracefully
            return None
        elif error_code == 'AccessDenied':
            # IAM policy doesn't allow s3:GetObject on this resource
            raise PermissionError(f"No access to s3://{bucket}/{key}") from e
        elif error_code == 'NoSuchBucket':
            raise ValueError(f"Bucket '{bucket}' does not exist") from e
        else:
            # Unknown error — re-raise for the caller
            raise

# DynamoDB conditional expression conflict
def create_order_safe(table, order_id: str, data: dict) -> bool:
    """Create an order only if it doesn't already exist."""
    from boto3.dynamodb.conditions import Attr
    try:
        table.put_item(
            Item={'order_id': order_id, **data},
            ConditionExpression=Attr('order_id').not_exists()
        )
        return True
    except ClientError as e:
        if e.response['Error']['Code'] == 'ConditionalCheckFailedException':
            return False  # Order already exists
        raise
